/*
 * fmod() test harness — prints (x_hex, y_hex, output_hex) triples.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x, double y)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    volatile double vy = y;
    g_acc += fmod(vx, vy);
#else
    double r = fmod(x, y);
    printf("%016llx %016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(y), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t x_bits, uint64_t y_bits)
{
    emit(u2d(x_bits), u2d(y_bits));
}

#ifndef EN_PERF
/* 7. Sweep through various ratios */
static void test_sweep(void)
{
    double ratios[] = { 1.1, 1.5, 2.0, 2.5, 3.0, 3.5, 4.0, 10.0 };
    int n = sizeof(ratios) / sizeof(ratios[0]);
    for (int i = 0; i < n; i++) {
        emit(ratios[i] * 10.0, 3.0);
        emit(-ratios[i] * 10.0, 3.0);
    }
}

/* 8. Sample across exponent range */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3fc0000000000000ULL, /* 0.125 */
        0x3fd0000000000000ULL, /* 0.25 */
        0x3fe0000000000000ULL, /* 0.5 */
        0x3fe8000000000000ULL, /* 0.75 */
        0x3ff0000000000000ULL, /* 1.0 */
        0x4000000000000000ULL, /* 2.0 */
        0x4008000000000000ULL, /* 3.0 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i], 0x3ff0000000000000ULL);
}

/* 9. Random sweep: 15x20 grid = 300 cases */
static void test_random_300(void)
{
    int nx = 15, ny = 20;
    for (int i = 0; i < nx; i++) {
        double x = -10.0 + 20.0 * (double)i / (double)(nx - 1);
        for (int j = 0; j < ny; j++) {
            double y = 0.1 + 4.9 * (double)j / (double)(ny - 1);
            emit(x, y);
        }
    }
}
#endif

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (14) --- */
    emit(0.0, 1.0);                                                               /* +0 / normal */
    emit(-0.0, 1.0);                                                              /* -0 / normal */
    emit(0.0, -1.0);                                                              /* +0 / negative normal */
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);                        /* qNaN / 1.0 */
    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL);                        /* sNaN / 1.0 */
    emit_u(0xfff8000000000000ULL, 0x3ff0000000000000ULL);                        /* -qNaN / 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);                        /* 1.0 / qNaN */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);                        /* +Inf / 1.0 -> NaN */
    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL);                        /* -Inf / 1.0 -> NaN */
    emit(1.0, 0.0);                                                               /* normal / +0 -> NaN */
    emit(-1.0, 0.0);                                                              /* normal / -0 -> NaN */
    emit_u(0x7ff0000000000000ULL, 0x7ff0000000000000ULL);                        /* +Inf / +Inf -> NaN */
    emit(1.0, INFINITY);                                                          /* normal / +Inf -> x */
    emit(-1.0, -INFINITY);                                                        /* normal / -Inf -> x */

    /* --- Section 2: Subnormal inputs (8) --- */
    emit_u(0x0000000000000001ULL, 0x3ff0000000000000ULL);                        /* min positive subnormal / 1.0 */
    emit_u(0x8000000000000001ULL, 0x3ff0000000000000ULL);                        /* min negative subnormal / 1.0 */
    emit_u(0x0008000000000000ULL, 0x3ff0000000000000ULL);                        /* mid subnormal / 1.0 */
    emit_u(0x8008000000000000ULL, 0x3ff0000000000000ULL);                        /* -mid subnormal / 1.0 */
    emit_u(0x000fffffffffffffULL, 0x3ff0000000000000ULL);                        /* max subnormal / 1.0 */
    emit_u(0x800fffffffffffffULL, 0x3ff0000000000000ULL);                        /* -max subnormal / 1.0 */
    emit_u(0x0000000000000001ULL, 0x0000000000000001ULL);                        /* min subnormal / min subnormal -> 0 */
    emit_u(0x000fffffffffffffULL, 0x0000000000000001ULL);                        /* max subnormal / min subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(DBL_MIN, 1.0);                                                           /* smallest normal / 1.0 */
    emit(-DBL_MIN, 1.0);                                                          /* -smallest normal / 1.0 */
    emit_u(0x0010000000000001ULL, 0x0010000000000000ULL);                        /* DBL_MIN+1ulp / DBL_MIN */
    emit(DBL_MAX, 1.0e300);                                                       /* DBL_MAX / large */
    emit(-DBL_MAX, 1.0e300);                                                      /* -DBL_MAX / large */
    emit(DBL_MAX, DBL_MAX);                                                       /* DBL_MAX / DBL_MAX -> 0 */

    /* --- Section 4: x < y (quotient = 0, result = x) (8) --- */
    emit(1.0, 2.0);                                                               /* x < y -> x */
    emit(-1.0, 2.0);                                                              /* -x < y -> -x */
    emit(0.5, 1.0);                                                               /* 0.5 / 1.0 -> 0.5 */
    emit(0.1, 1.0);                                                               /* small / large */
    emit(1.0e-10, 1.0);                                                           /* very small / 1.0 */
    emit(1.0e100, 1.0e200);                                                       /* large / larger */
    emit(DBL_MIN, DBL_MAX);                                                       /* min / max -> min */
    emit(3.14159265358979, 10.0);                                                 /* pi < 10 -> pi */

    /* --- Section 5: x = y (result = 0) (6) --- */
    emit(1.0, 1.0);                                                               /* x = y -> 0 */
    emit(-1.0, -1.0);                                                             /* -x = -y -> -0 */
    emit(0.5, 0.5);                                                               /* 0.5 = 0.5 -> 0 */
    emit(1.0e100, 1.0e100);                                                       /* large equal -> 0 */
    emit(DBL_MAX, DBL_MAX);                                                       /* max / max -> 0 (dup of boundary, kept for section cohesion) */
    emit_u(0x3ff921fb54442d18ULL, 0x3ff921fb54442d18ULL);                        /* pi/2 / pi/2 -> 0 */

    /* --- Section 6: Exact multiples x = k*y (result = 0) (8) --- */
    emit(10.0, 5.0);                                                              /* x = 2*y */
    emit(15.0, 5.0);                                                              /* x = 3*y */
    emit(100.0, 10.0);                                                            /* x = 10*y */
    emit(-20.0, 4.0);                                                             /* negative exact */
    emit(8.0, 2.0);                                                               /* power-of-2 exact */
    emit(1024.0, 256.0);                                                          /* large power-of-2 exact */
    emit(1.5, 0.5);                                                               /* fractional exact: 1.5 = 3 * 0.5 */
    emit(0.75, 0.25);                                                             /* 0.75 = 3 * 0.25 */

    /* --- Section 7: Basic integer and fractional cases (10) --- */
    emit(5.0, 2.0);                                                               /* 5 mod 2 = 1 */
    emit(5.5, 2.5);                                                               /* 5.5 mod 2.5 = 0.5 */
    emit(-5.0, 2.0);                                                              /* negative x */
    emit(5.0, -2.0);                                                              /* negative y */
    emit(-5.0, -2.0);                                                             /* both negative */
    emit(3.0, 2.0);                                                               /* 3 mod 2 = 1 */
    emit(10.0, 3.0);                                                              /* 10 mod 3 = 1 */
    emit(7.0, 2.5);                                                               /* 7 mod 2.5 = 2.0 */
    emit(22.0, 7.0);                                                              /* 22 mod 7 = 1 */
    emit(355.0, 113.0);                                                           /* pi approximation ratio */

    /* --- Section 8: Spread across exponent range (10) --- */
    emit(1.0e-100, 1.0e-50);                                                      /* tiny / small */
    emit(1.0e-200, 1.0e-100);                                                     /* very tiny / tiny */
    emit(1.0e50, 1.0e25);                                                         /* large / medium */
    emit(1.0e100, 1.0e50);                                                        /* very large / large */
    emit(1.0e200, 1.0e100);                                                       /* huge / very large */
    emit(DBL_MAX, 1.0e100);                                                       /* DBL_MAX / large */
    emit(-1.0e100, 1.0e50);                                                       /* negative large */
    emit(1.0e50, 1.0e100);                                                        /* x < y in large range */
    emit(1.0e-50, 1.0e-100);                                                      /* small / tiny (x > y) */
    emit(1.23456789012345e15, 1.0e10);                                            /* large irrational / 1e10 */

    /* --- Section 9: ULP neighbors near key values (12) --- */
    emit_u(0x3ff0000000000000ULL, 0x3fefffffffffffffULL);                        /* 1.0 / (1.0-1ulp) */
    emit_u(0x3ff0000000000001ULL, 0x3ff0000000000000ULL);                        /* (1.0+1ulp) / 1.0 */
    emit_u(0x3fefffffffffffffULL, 0x3ff0000000000000ULL);                        /* (1.0-1ulp) / 1.0 -> nearly 1 */
    emit_u(0x400921fb54442d18ULL, 0x3ff921fb54442d18ULL);                        /* pi / (pi/2) */
    emit_u(0x400921fb54442d17ULL, 0x3ff921fb54442d18ULL);                        /* (pi-1ulp) / (pi/2) */
    emit_u(0x400921fb54442d19ULL, 0x3ff921fb54442d18ULL);                        /* (pi+1ulp) / (pi/2) */
    emit_u(0x4000000000000000ULL, 0x3ff0000000000000ULL);                        /* 2.0 / 1.0 -> 0 */
    emit_u(0x4000000000000001ULL, 0x4000000000000000ULL);                        /* (2.0+1ulp) / 2.0 */
    emit_u(0x3fffffffffffffffULL, 0x3ff0000000000000ULL);                        /* (2.0-1ulp) / 1.0 */
    emit_u(0x0010000000000000ULL, 0x000fffffffffffffULL);                        /* DBL_MIN / (max subnormal) */
    emit_u(0x0010000000000001ULL, 0x0010000000000000ULL);                        /* (DBL_MIN+1ulp) / DBL_MIN */
    emit_u(0x7fefffffffffffffULL, 0x7feffffffffffff0ULL);                        /* DBL_MAX / (DBL_MAX-16ulp) */

    /* --- Section 10: Stress cases (18) --- */
    emit(100.0, 30.0);                                                            /* integer-like */
    emit(1.0, 1.0e-15);                                                           /* x >> y, many quotient bits */
    emit(1.0, 1.0e-300);                                                          /* extreme x >> y */
    emit(1.0e300, 1.0e-300);                                                      /* extreme ratio */
    emit(M_PI, 1.0);                                                              /* pi mod 1.0 */
    emit(M_PI, M_PI / 4.0);                                                       /* pi mod pi/4 -> 0 */
    emit(M_E, 1.0);                                                               /* e mod 1.0 */
    emit(M_LN2, 1.0e-1);                                                          /* ln2 mod 0.1 */
    emit_u(0x3fe62e42fefa39efULL, 0x3fe0000000000000ULL);                        /* ln2 / 0.5 */
    emit_u(0x40862e42fefa39efULL, 0x3fe62e42fefa39efULL);                        /* exp-overflow-thresh / ln2 */
    emit(1.0, 3.0);                                                               /* x < y, result = x */
    emit(-1.0, 3.0);                                                              /* negative x < y */
    emit(2.9999999999999996, 3.0);                                                /* just below 3.0 divided by 3.0 */
    emit_u(0x4023ffffffffffff ULL, 0x4024000000000000ULL);                       /* (10.0-1ulp) / 10.0 */
    emit(1.0, 0.1);                                                               /* repeated-subtraction stress */
    emit(1.0, 0.3);                                                               /* non-representable divisor */
    emit(-0.0, -1.0);                                                             /* -0 / negative y -> -0 */
    emit_u(0x7fefffffffffffffULL, 0x0010000000000000ULL);                        /* DBL_MAX / DBL_MIN -> large remainder */
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}
